import { Component, Host, h, State } from '@stencil/core';
export class StencilVirtualScrollDemo {
  constructor() {
    this.mode = 'none';
  }
  renderItem(props) {
    return h("p", null,
      h("b", null, props.name),
      h("span", null,
        " (",
        props.desc,
        ")"),
      h("br", null),
      this.mode === props.name
        ? h("button", { onClick: () => this.mode = 'none' }, "Hide Demo")
        : h("button", { onClick: () => this.mode = props.name }, "Show Demo"));
  }
  renderDemo() {
    if (this.mode === 'virtual-scroll') {
      return h("div", { class: 'demo' },
        h("virtual-scroll-demo", null));
    }
    if (this.mode === 'virtual-scroll-list') {
      return h("div", { class: 'demo' },
        h("virtual-scroll-list-demo", null));
    }
  }
  render() {
    return (h(Host, null,
      h("h1", null, "stencil-virtual-scroll Demo"),
      this.renderItem({ name: 'virtual-scroll', desc: 'fixed-size cells in grid view' }),
      this.renderItem({ name: 'virtual-scroll-list', desc: 'vary-height items in list view' }),
      this.renderDemo()));
  }
  static get is() { return "stencil-virtual-scroll-demo"; }
  static get encapsulation() { return "shadow"; }
  static get originalStyleUrls() { return {
    "$": ["stencil-virtual-scroll-demo.css"]
  }; }
  static get styleUrls() { return {
    "$": ["stencil-virtual-scroll-demo.css"]
  }; }
  static get states() { return {
    "mode": {}
  }; }
}
